# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

from strawberry import Schema, field
from typing import List
from sqlalchemy import create_engine, Column, Integer, String, Text
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker

Base = declarative_base()

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String(100), nullable=False)
    description = Column(Text)

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    content = Column(Text, nullable=False)
    product_id = Column(Integer, ForeignKey('products.id'), nullable=False)

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True)
    name = Column(String(100), nullable=False)
    email = Column(String(100), nullable=False)

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String(100), nullable=False)

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    url = Column(String(100), nullable=False)
    product_id = Column(Integer, ForeignKey('products.id'), nullable=False)

engine = create_engine('sqlite:///data.db')
SessionLocal = sessionmaker(bind=engine)
Base.metadata.create_all(engine)

class Query:
    @field
    def product(self, id: int):
        db = SessionLocal()
        product = db.query(Product).filter_by(id=id).first()
        if not product:
            raise ValueError("Product not found")
        
        # Related data
        reviews = db.query(Review).filter_by(product_id=id)
        sellers = db.query(Seller).join(Review, Review.product_id == Product.id).filter_by(product_id=id)
        categories = db.query(Category).join(Product, Product.category_id == Category.id).filter_by(id=id)
        images = db.query(Image).filter_by(product_id=id)

        return {
            'product': product,
            'reviews': reviews.all(),
            'sellers': sellers.all(),
            'categories': categories.all(),
            'images': [img.url for img in images],
        }

class Mutation:
    @field
    def create_product(self, name: str, description: str):
        db = SessionLocal()
        product = Product(name=name, description=description)
        db.add(product)
        db.commit()

schema = Schema(Query=Query, Mutation=Mutation)